import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import API from '../services/api';
import './AdminAnalytics.css';

function AdminAnalytics() {
  const { user } = useAuth();
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [listings, setListings] = useState([]);

  useEffect(() => {
    loadListings();
  }, []);

  const loadListings = async () => {
    setLoading(true);
    try {
      // Используем рабочий эндпоинт из listings
      const response = await API.get('/listings/?limit=50');
      setListings(response.data);
    } catch (err) {
      console.error('Ошибка:', err);
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };



  if (loading) return <div className="loader">Загрузка...</div>;
  if (error) return <div className="error">Ошибка: {error}</div>;

  // Простая аналитика на основе listings
  const totalListings = listings.length;
  const activeListings = listings.filter(l => l.listing_status_id === 1).length;
  const avgPrice = listings.reduce((sum, l) => sum + (l.price || 0), 0) / listings.length || 0;

  return (
    <div className="analytics-page">
      <h1>📊 Простая аналитика</h1>

      <div className="metrics-grid">
        <div className="metric-card">
          <h3>Всего объявлений</h3>
          <p className="metric-value">{totalListings}</p>
        </div>
        <div className="metric-card">
          <h3>Активных</h3>
          <p className="metric-value">{activeListings}</p>
        </div>
        <div className="metric-card">
          <h3>Средняя цена</h3>
          <p className="metric-value">{Math.round(avgPrice).toLocaleString()} ₽</p>
        </div>
      </div>

      <div className="analytics-card">
        <h2>📋 Последние объявления</h2>
        <div className="listings-list">
          {listings.slice(0, 10).map((item, index) => (
            <div key={item.listing_id || index} className="listing-item">
              <span className="rank">{index + 1}</span>
              <div className="listing-info">
                <h4>{item.title || 'Без названия'}</h4>
                <p>{item.address || 'Адрес не указан'}</p>
              </div>
              <div className="listing-stats">
                <span className="price">
                  {item.price ? item.price.toLocaleString() : 0} ₽
                </span>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

export default AdminAnalytics;
